mapper.select:
SELECT FAC_CODE, FAC_NAME, FAC_NO, FAC_GUBN, FAC_PLC, FAC_MAKE, FAC_ABLE, FAC_STATE, FAC_MAN1, FAC_FILE_NAME FROM tb_fac
AND FAC_NAME LIKE CONCAT('%',#{kwFacName},'%')
AND FAC_NO LIKE CONCAT('%',#{kwFacNo},'%')
AND FAC_GUBN = #{kwFacGubn}
ORDER BY FAC_CODE LIMIT #{offset}, #{pageSize}
